PROG11_1.PAS   Thuật toán đường mở tìm bộ ghép cực đại
program MatchingProblem;
const
  max   100;
var
  m, n: Integer;
  a: array 1..max, 1..max  of Boolean;
  matchX, matchY: array 1..max  of Integer;
  Trace: array 1..max  of Integer;
procedure Enter;
 Đọc dữ liệu,  từ thiết bị nhập chuẩn  
var
  i, j: Integer;
begin
  FillChar a, SizeOf a , False ;
  ReadLn m, n ;

Lý thuyết đồ thị
Lê Minh Hoàng
  92  
  while not SeekEof do
    begin
      ReadLn i, j ;
      a i, j  :  True;
    end;
end;
procedure Init;
 Khởi tạo bộ ghép rỗng 
begin
  FillChar matchX, SizeOf matchX , 0 ;
  FillChar matchY, SizeOf matchY , 0 ;
end;
 Tìm đường mở, nếu thấy trả về một Y_đỉnh chưa ghép là đỉnh kết thúc đường mở, nếu không thấy trả về 0 
function FindAugmentingPath: Integer;
var
  Queue: array 1..max  of Integer;
  i, j, first, last: Integer;
begin
  FillChar Trace, SizeOf Trace , 0 ;
 Trace j    X_đỉnh liền trước Y j  trên đường mở 
  last :  0;
 Khởi tạo hàng đợi rỗng 
  for i :  1 to m do
 Đẩy tất cả những X_đỉnh chưa ghép vào hàng đợi 
    if matchX i    0 then
      begin
        Inc last ;
        Queue last  :  i;
      end;
   Thuật toán tìm kiếm theo chiều rộng 
  first :  1;
  while first    last do
    begin
      i :  Queue first ; Inc first ;
 Lấy một X_đỉnh ra khỏi Queue  X i   
      for j :  1 to n do
 Xét những Y_đỉnh chưa thăm kề với X i  qua một cạnh chưa ghép 
        if  Trace j    0  and a i, j  and  matchX i     j  then
          begin  lệnh if trên hơi thừa đk matchX i     j, điều kiện Trace j    0 đã bao hàm luôn điều kiện này rồi 
            Trace j  :  i;
 Lưu vết đường đi 
            if matchY j    0 then
 Nếu j chưa ghép thì ghi nhận đường mở và thoát ngay 
              begin
                FindAugmentingPath :  j;
                Exit;
              end;
            Inc last ;
 Đẩy luôn matchY j  vào hàng đợi 
            Queue last  :  matchY j ;
          end;
    end;
  FindAugmentingPath :  0;
 Ở trên không Exit được tức là không còn đường mở 
end;
 Nới rộng bộ ghép bằng đường mở kết thúc ở f Y 
procedure Enlarge f: Integer ;
var
  x, next: Integer;
begin
  repeat
    x :  Trace f ;
    next :  matchX x ;
    matchX x  :  f;
    matchY f  :  x;
    f :  next;
  until f   0;
end;
procedure Solve;
 Thuật toán đường mở 
var
next
... f
x

Lý thuyết đồ thị
Lê Minh Hoàng
  93  
  finish: Integer;
begin
  repeat
    finish :  FindAugmentingPath;
 Đầu tiên thử tìm một đường mở 
    if finish    0 then Enlarge finish ;
 Nếu thấy thì tăng cặp và lặp lại 
  until finish   0;
 Nếu không thấy thì dừng 
end;
procedure PrintResult;
 In kết quả 
var
  i, Count: Integer;
begin
  WriteLn  Match:   ;
  Count :  0;
  for i :  1 to m do
    if matchX i     0 then
      begin
        Inc Count ;
        WriteLn Count,    X  , i,    - Y  , matchX i ,     ;
      end;
end;
begin
  Assign Input,  MATCH.INP  ; Reset Input ;
  Assign Output,  MATCH.OUT  ; Rewrite Output ;
  Enter;
  Init;
  Solve;
  PrintResult;
  Close Input ;
  Close Output ;
end. Khảo sát tính đúng đắn của thuật toán cho ta một kết quả khá thú vị:
Nếu ta thêm một đỉnh A và cho thêm m cung
từ A tới tất cả những đỉnh của tập X, thêm
một đỉnh B và nối thêm n cung từ tất cả các
đỉnh của Y tới B. Nếu đặt khả năng thông
qua của các cung đều là 1 sau đó tìm luồng
cực đại trên mạng bằng thuật toán Ford-
Fulkerson thì theo định lý về tính nguyên,
luồng tìm được trên các cung đều phải là số nguyên  tức là bằng 1 hoặc 0 . Khi đó dễ thấy rằng
những cung có luồng 1 từ tập X tới tập Y sẽ cho ta một bộ ghép lớn nhất.

