PROG08_5.PAS   Thuật toán Floyd
program Shortest_Path_by_Floyd;
const
  max   100;
  maxC   10000;
var
  c: array 1..max, 1..max  of Integer;
  Trace: array 1..max, 1..max  of Integer;  Trace u, v    Đỉnh liền sau u trên đường đi từ u tới v 
  n, S, F: Integer;
procedure LoadGraph;
 Nhập dữ liệu, đồ thị không được có chu trình âm 
var
  i, m: Integer;
  u, v: Integer;
begin
  ReadLn n, m, S, F ;
  for u :  1 to n do
    for v :  1 to n do
      if u   v then c u, v  :  0 else c u, v  :  maxC;
  for i :  1 to m do ReadLn u, v, c u, v  ;
end;
procedure Floyd;
var
  k, u, v: Integer;
begin
  for u :  1 to n do
    for v :  1 to n do Trace u, v  :  v;  Giả sử đường đi ngắn nhất giữa mọi cặp đỉnh là đường trực tiếp 
   Thuật toán Floyd 
  for k :  1 to n do
    for u :  1 to n do
      for v :  1 to n do
        if c u, v    c u, k    c k, v  then
 Đường đi từ qua k tốt hơn 
          begin
            c u, v  :  c u, k    c k, v ;
 Ghi nhận đường đi đó thay cho đường cũ 
            Trace u, v  :  Trace u, k ;
 Lưu vết đường đi 
          end;
end;
procedure PrintResult;
 In đường đi từ S tới F 
begin
  if c S, F    maxC
    then WriteLn  Path from  , S,   to  , F,   not found  
  else
    begin
      WriteLn  Distance from  , S,   to  , F,  :  , c S, F  ;
      repeat

Lý thuyết đồ thị
