  70  
        Write S,  -   ;
        S :  Trace S, F ; 
 Nhắc lại rằng Trace S, F  là đỉnh liền sau S trên đường đi tới F 
      until S   F;
      WriteLn F ;
    end;
end;
begin
  Assign Input,  MINPATH.INP  ; Reset Input ;
  Assign Output,  MINPATH.OUT  ; Rewrite Output ;
  LoadGraph;
  Floyd;
