program AssignmentProblemSolve;
const
  max   100;
  maxC   10001;
var
  c: array 1..max, 1..max  of Integer;
  Fx, Fy, matchX, matchY: array 1..max  of Integer;
  Trace, Queue, d, arg: array 1..max  of Integer;
  first, last: Integer;
  start, finish: Integer;
  m, n, k: Integer;
procedure Enter;
 Nhập dữ liệu 
var
  i, j: Integer;
begin
  ReadLn m, n ;
  if m   n then k :  m else k :  n;
  for i :  1 to k do
    for j :  1 to k do c i, j  :  maxC;
  while not SeekEof do ReadLn i, j, c i, j  ;
end;
procedure Init;
 Khởi tạo bộ ghép rỗng và hai dãy đối ngẫu Fx, Fy 
var
  i, j: Integer;
begin
  FillChar matchX, SizeOf matchX , 0 ;
  FillChar matchY, SizeOf matchY , 0 ;
  for i :  1 to k do
    begin
      Fx i  :  maxC;
      for j :  1 to k do
        if c i, j    Fx i  then Fx i  :  c i, j ;

Lý thuyết đồ thị
Lê Minh Hoàng
  108  
    end;
  for j :  1 to k do
    begin
      Fy j  :  maxC;
      for i :  1 to k do
        if c i, j  - Fx i    Fy j  then Fy j  :  c i, j  - Fx i ;
    end;
end;
function GetC i, j: Integer : Integer;
 Hàm trả về trọng số cạnh  X i , Y j   
begin
  GetC :  c i, j  - Fx i  - Fy j ;
end;
procedure InitBFS;
 Thủ tục khởi tạo trước khi tìm cách ghép start X 
var
  y: Integer;
begin
   Hàng đợi chỉ gồm mỗi một đỉnh Start   cây pha khởi tạo chỉ có 1 đỉnh start 
  first :  1; last :  1;
  Queue 1  :  start;
   Khởi tạo các Y_đỉnh đều chưa thăm   Trace y    0,  y 
  FillChar Trace, SizeOf Trace , 0 ;
   Khởi tạo các d y  
  for y :  1 to k do
    begin
      d y  :  GetC start, y ;
 d y  là khoảng cách từ y tới cây pha gốc start 
      arg y  :  start;
 arg y  là X_đỉnh thuộc cây pha tạo ra khoảng cách đó 
    end;
  finish :  0;
end;
procedure Push v: Integer ;
 Đẩy một đỉnh v X vào hàng đợi 
begin
  Inc last ; Queue last  :  v;
end;
function Pop: Integer;
 Rút một X_đỉnh khỏi hàng đợi, trả về trong kết quả hàm 
begin
  Pop :  Queue first ; Inc first ;
end;
procedure FindAugmentingPath;
 Thủ tục tìm đường mở 
var
  i, j, w: Integer;
begin
  repeat
    i :  Pop;
 Rút một đỉnh X i  khỏi hàng đợi 
    for j :  1 to k do
 Quét những Y_đỉnh chưa thăm 
      if Trace j    0 then
        begin
          w :  GetC i, j ;
 xét cạnh  X i , Y j   
          if w   0 then
 Nếu là 0_cạnh 
            begin
              Trace j  :  i;
 Lưu vết đường đi 
              if matchY j    0 then
 Nếu j chưa ghép thì ghi nhận nơi kết thúc đường mở và thoát 
                begin
                  finish :  j;
                  Exit;
                end;
              Push matchY j  ;
 Nếu j đã ghép thì đẩy tiếp matchY j  vào hàng đợi 
            end;
          if d j    w then
 Cập nhật lại khoảng cách d j  nếu thấy cạnh  X i , Y j   ngắn hơn khoảng cách này 
            begin

