              d j  :  w;
              arg j  :  i;
            end;
        end;
  until first   last;
end;
 Xoay các trọng số cạnh 
procedure SubX_AddY;
var
  Delta: Integer;
  x, y: Integer;
begin
   Trước hết tính     giá trị nhỏ nhất trọng số các d y , với y Y chưa thăm  y không thuộc cây pha  
  Delta :  maxC;
  for y :  1 to k do
    if  Trace y    0  and  d y    Delta  then Delta :  d y ;
   Trừ trọng số những cạnh liên thuộc với start X đi   
  Fx start  :  Fx start    Delta;
  for y :  1 to k do
 Xét các đỉnh y Y 
    if Trace y     0 then
 Nếu y thuộc cây pha 
      begin
        x :  matchY y ;
 Thì x   matchY y  cũng phải thuộc cây pha 
        Fy y  :  Fy y  - Delta;
 Cộng trọng số những cạnh liên thuộc với y lên   
        Fx x  :  Fx x    Delta;
 Trừ trọng số những cạnh liên thuộc với x đi   
      end
    else
      d y  :  d y  - Delta;
 Nếu y   cây pha thì sau bước xoay, khoảng cách từ y đến cây pha sẽ giảm   
   Chuẩn bị tiếp tụcBFS 
  for y :  1 to k do
    if  Trace y    0  and  d y    0  then
 Thăm luôn những đỉnh y Y tạo với cây pha một 0_cạnh 
      begin
        Trace y  :  arg y ;
 Lưu vết đường đi 
        if matchY y    0 then
 Nếu y chưa ghép thì ghi nhận đỉnh kết thúc đường mở và thoát ngay 
          begin
            finish :  y;
            Exit;
          end;
        Push matchY y  ;
 Nếu y đã ghép thì đẩy luôn matchY y  vào hàng đợi để chờ loang tiếp 
      end;
end;
procedure Enlarge;
 Nới rộng bộ ghép bằng đường mở kết thúc ở finish 
var
  x, next: Integer;
begin
  repeat
    x :  Trace finish ;
    next :  matchX x ;
    matchX x  :  finish;
    matchY finish  :  x;
    finish :  Next;
  until finish   0;
end;
